#include<bits/stdc++.h>
using namespace std;
long long babashigeX(long long a,long long b,long long c){
	long long sb=0;
	for(long long i=0;i<a;i++){
		sb+=(i+1)*(i*10+2)/2;
	}
	sb+=b*((b-1)*10+2)/2+c+1;
	return sb;
}
int main()
{
	int t,n,a,b,c,d,e,f;
	long long sum1,sum2;
	cin>>t;
	while(t--){
		cin>>n>>a>>b>>c>>d>>e>>f;
		sum1=babashigeX(a,b,c),sum2=babashigeX(d,e,f);
		if(sum2<sum1)sum2+=babashigeX(n,0,0)-1;
		cout<<sum2-sum1<<endl;
	}
	return 0;
}
